import React, { useState, useEffect, useRef } from 'react';
import './matrix.css';
import Handler from '../api/Data';

const Matrix = () => {
  const [rows_cols, setRowsCols] = useState(5);
  const [grid, setGrid] = useState([]);
  const [sizeplayer, setSize] = useState(0);
  const [data, setData] = useState(null);
  const matrixRef = useRef([]);
  const [ifwin, setIfwin] = useState(0);

  useEffect(() => {
    async function fetchData() {
      const response = await fetch("http://localhost:5000/grid");
      const jsonData = await response.json();
      setData(jsonData);
    }
    fetchData();
  }, []);

  useEffect(() => {
    let newGrid = [];
    for (let i = 0; i < rows_cols; i++) {
      let row = [];
      for (let j = 0; j < rows_cols; j++) {
        row.push(0);
      }
      newGrid.push(row);
    }
    setGrid(newGrid);
  }, [rows_cols]);

  const handleBoxClick = (row, col) => {
    let newGrid = [...grid];
    newGrid[row][col] = newGrid[row][col] === 0 ? 1 : 0;
    setGrid(newGrid);
  };

  const renderMatrix = () => {
    let matrix = [];
    for (let i = 0; i < rows_cols; i++) {
      let row = [];
      for (let j = 0; j < rows_cols; j++) {
        if (grid[i] && grid[i][j] !== undefined) {
          row.push(
            <div
              className="grid-square"
              style={{ backgroundColor: grid[i][j] === 0 ? "white" : "black" }}
              onClick={() => handleBoxClick(i, j)}
              key={`${i}-${j}`}
              ref={ref => matrixRef.current.push(ref)}
            />
          );
        }
      }
      matrix.push(<div className="grid-row" style={{ display: 'flex', flexDirection: 'column' }} key={i}>{row}</div>);
    }
    return matrix;
  };

  useEffect(() => {
    const checkGrid = () => {
      let index = 0;
      for (let i = 0; i < rows_cols; i++) {
        for (let j = 0; j < rows_cols; j++) {
          const matrixValue = matrixRef.current[index].style.backgroundColor === "black" ? 1 : 0;
          if (data[i][j] !== matrixValue) {
            console.log("Grids are different");
            setIfwin(1);
            return;
          }
          index++;
        }
      }
      console.log("Grids are the same");
    };

    if (data && matrixRef.current.length === rows_cols * rows_cols) {
      checkGrid();
    }
  }, [data, rows_cols, grid]);

  const handleSetSize = () => {
    setSize(rows_cols);
    matrixRef.current = [];
    setIfwin(0);
  };

  const handleSizeChange = (e) => {
    setRowsCols(parseInt(e.target.value,
      10));
    };

    return (
    <div className="App">
    <h1>Grid of Squares</h1>
    <label>
    Number of Rows/Columns:
    <input type="number" value={rows_cols} onChange={handleSizeChange} />
    </label>
    <div className="grid-container">
    {Array(rows_cols * rows_cols)
    .fill()
    .map((_, index) => (
    <div
    key={index}
    className="grid-item"
    style={{ backgroundColor: randomColor() }}
    ></div>
    ))}
    </div>
    </div>
    );
    }

    export default Matrix;
